function Pill({label,sel,onClick,radio}){
  return(
    <div onClick={onClick} style={{display:"flex",alignItems:"center",gap:8,background:sel?"#F7EDED":"#fff",border:`1.5px solid ${sel?W:BD}`,borderRadius:8,padding:"9px 12px",cursor:"pointer",fontSize:13,color:TX,fontWeight:sel?600:400,userSelect:"none",lineHeight:1.4}}>
      <span style={{width:15,height:15,minWidth:15,border:`1.5px solid ${sel?W:BD}`,borderRadius:radio?"50%":3,background:sel?W:"transparent",display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,color:"#fff",flexShrink:0}}>{sel?"✓":""}</span>
      {label}
    </div>
  );
}
function PillGrid({opts,val,setVal,radio,cols=2}){
  const click=(v)=>{if(radio){setVal(v);return;}setVal(p=>{const a=p||[];return a.includes(v)?a.filter(x=>x!==v):[...a,v];});};
  return(<div style={{display:"grid",gridTemplateColumns:`repeat(${cols},1fr)`,gap:6}}>{opts.map(o=><Pill key={o.v} label={o.l} radio={radio} sel={radio?val===o.v:(val||[]).includes(o.v)} onClick={()=>click(o.v)}/>)}</div>);
}
function Label({t}){return <div style={{fontSize:11,fontWeight:700,color:MT,marginBottom:6,textTransform:"uppercase",letterSpacing:"0.6px"}}>{t}</div>;}
function Bloco({label,children}){return <div style={{marginBottom:14}}><Label t={label}/>{children}</div>;}
function SecBox({title,children}){
  return(
    <div style={{border:`1px solid ${BD}`,borderRadius:12,marginBottom:16,overflow:"hidden"}}>
      <div style={{background:RL,padding:"9px 16px"}}><span style={{fontFamily:"Georgia,serif",fontSize:13,fontWeight:700,color:W}}>{title}</span></div>
      <div style={{padding:"14px 16px 8px",background:"#fff"}}>{children}</div>
    </div>
  );
}

