function calcularProtocolos(obsC,alters,objs){
  const temAcne=alters.includes("Acne ativa");
  const temMelasma=alters.includes("Melasma");
  const temPIH=alters.includes("PIH")||alters.includes("Melanose solar");
  const temFlacidez=alters.includes("Flacidez")||alters.includes("Linhas de expressão");
  const temSensib=alters.includes("Sensibilidade/vermelhidão")||alters.includes("Eritema")||obsC==="Sensível";
  const temResseq=alters.includes("Ressecamento/descamação");
  const temEnvelh=obsC==="Envelhecida";
  const temOpaca=alters.includes("Poros dilatados")||alters.includes("Efélides")||objs.includes("Revitalização e luminosidade")||objs.includes("Hidratar e restaurar barreira");
  const resultado=[];

  if(temSensib||temResseq){
    resultado.push({...LINHAS.calmskin,ordem:resultado.length+1,
      prioridade:"🔴 Iniciar por aqui — barreira comprometida",
      just:`Barreira comprometida${temSensib?" — sensibilidade/eritema":""}${temResseq?" — ressecamento/descamação":""}. Estabilizar antes de qualquer protocolo ativo. Critério SASSQ para progressão.`,
    });
  }
  if(temAcne||objs.includes("Reduzir acne e oleosidade")){
    resultado.push({...LINHAS.pureskin,ordem:resultado.length+1,
      prioridade:(temSensib||temResseq)?"🟡 Após CalmSkin 3.0":"🔴 Iniciar por aqui",
      just:`Acne ativa identificada${temPIH?" com HPI associada":""}. Protocolo corneoterapêutico: barreira + controle inflamatório folicular.`,
    });
  }
  if(temMelasma||temPIH||objs.includes("Clarear manchas")){
    resultado.push({...LINHAS.lumenskin,ordem:resultado.length+1,
      prioridade:(temSensib||temResseq)?"🟡 Após CalmSkin 3.0":temAcne?"🟡 Após controle da acne":"🔴 Iniciar por aqui",
      just:`${temMelasma?"Melasma identificado":""}${temPIH?" + HPI/manchas":""}. Nunca clarear pele inflamada — fotoproteção com cor é contrato obrigatório.`,
    });
  }
  if(temFlacidez||temEnvelh||objs.includes("Rejuvenescimento global")||objs.includes("Estimular colágeno")){
    resultado.push({...LINHAS.liftskin,ordem:resultado.length+1,
      prioridade:temAcne?"🟡 Após controle da acne (microagulhamento proibido com acne ativa)":resultado.length>0?"🟡 Conduzir em paralelo ou sessões pares":"🔴 Iniciar por aqui",
      just:`${temFlacidez?"Flacidez/linhas de expressão":""}${temEnvelh?" em pele envelhecida":""}. 11 sessões em 3 fases. RF NUNCA na mesma sessão que microagulhamento.`,
    });
  }
  if(resultado.length===0||temOpaca){
    resultado.push({...LINHAS.glowskin,ordem:resultado.length+1,
      prioridade:resultado.length===0?"🔴 Iniciar por aqui":"🟢 Em paralelo ou como manutenção",
      just:resultado.length===0
        ?"Pele sem alterações graves ativas. Protocolo de revitalização bioenergética e tratamento de olheiras."
        :"Objetivo de luminosidade/revitalização — conduzir em alternância com o protocolo principal.",
    });
  }
  return resultado;
}

